import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { cronGuard } from '../../pretool/cron-guard.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'CronCreate',
    session_id: 'test-session',
    tool_input: { schedule: '*/5 * * * *', prompt: 'check CI' },
    ...overrides,
  };
}

let testCtx: ReturnType<typeof createTestContext>;

describe('cronGuard', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
    // Clean environment for each test
    delete process.env.CLAUDE_CODE_DISABLE_CRON;
    delete process.env.CI;
    delete process.env.GITHUB_ACTIONS;
    delete process.env.GITLAB_CI;
    delete process.env.CODEBUILD_BUILD_ID;
  });

  it('allows CronCreate in normal interactive session', () => {
    const result = cronGuard(makeInput(), testCtx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('ignores non-CronCreate tools', () => {
    const result = cronGuard(makeInput({ tool_name: 'Bash' }), testCtx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('blocks when CLAUDE_CODE_DISABLE_CRON=1', () => {
    process.env.CLAUDE_CODE_DISABLE_CRON = '1';

    const result = cronGuard(makeInput(), testCtx);

    expect(result.continue).toBe(false);
    expect(result.stopReason).toContain('CLAUDE_CODE_DISABLE_CRON');
  });

  it('blocks when CI=true', () => {
    process.env.CI = 'true';

    const result = cronGuard(makeInput(), testCtx);

    expect(result.continue).toBe(false);
    expect(result.stopReason).toContain('CI=true');
  });

  it('blocks when GITHUB_ACTIONS=true', () => {
    process.env.GITHUB_ACTIONS = 'true';

    const result = cronGuard(makeInput(), testCtx);

    expect(result.continue).toBe(false);
    expect(result.stopReason).toContain('GITHUB_ACTIONS');
  });

  it('blocks when GITLAB_CI=true', () => {
    process.env.GITLAB_CI = 'true';

    const result = cronGuard(makeInput(), testCtx);

    expect(result.continue).toBe(false);
    expect(result.stopReason).toContain('GITLAB_CI');
  });

  it('blocks when CODEBUILD_BUILD_ID is set', () => {
    process.env.CODEBUILD_BUILD_ID = 'build:12345';

    const result = cronGuard(makeInput(), testCtx);

    expect(result.continue).toBe(false);
    expect(result.stopReason).toContain('CodeBuild');
  });

  it('suggests ScheduleWakeup in block message', () => {
    process.env.CI = 'true';

    const result = cronGuard(makeInput(), testCtx);

    expect(result.stopReason).toContain('ScheduleWakeup');
  });
});
